head.b:skin:
/* FACEBOOK DEEP ARCHITECTURE */
:root {
    --primary: #2979ff;
    --primary-soft: rgba(41, 121, 255, 0.1);
    --bg: #f0f2f5;
    --surface: #ffffff;
    --text: #050505;
    --text-sub: #65676b;
    --border: #e4e6eb;
    --shadow: 0 2px 4px rgba(0,0,0,0.08), 0 12px 24px rgba(0,0,0,0.04);
    --glass: rgba(255, 255, 255, 0.85);
    --blur: blur(12px);
    --radius: 12px;
    --anim: 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
}

/* Dark Mode (Auto-detect preference or toggle) */
@media (prefers-color-scheme: dark) {
    /* Uncomment to force dark mode by default
    :root {
        --bg: #18191a;
        --surface: #242526;
        --text: #e4e6eb;
        --text-sub: #b0b3b8;
        --border: #3e4042;
        --glass: rgba(36, 37, 38, 0.85);
    } */
}

* { margin: 0; padding: 0; box-sizing: border-box; outline: none; }
body { font-family: 'Inter', sans-serif; background: var(--bg); color: var(--text); padding-top: 70px; overflow-y: scroll; }

/* --- SKELETON LOADING ANIMATION --- */
.skeleton { background: linear-gradient(90deg, var(--border) 25%, #f0f2f5 50%, var(--border) 75%); background-size: 200% 100%; animation: shimmer 1.5s infinite; border-radius: 4px; }
@keyframes shimmer { 0% { background-position: 200% 0; } 100% { background-position: -200% 0; } }

/* --- HEADER (Glassmorphism) --- */
.app-header {
    position: fixed; top: 0; left: 0; right: 0; height: 60px;
    background: var(--glass); backdrop-filter: var(--blur);
    border-bottom: 1px solid var(--border); z-index: 1000;
    display: flex; align-items: center; justify-content: space-between; padding: 0 20px;
    box-shadow: 0 4px 10px rgba(0,0,0,0.02);
}
.logo { font-size: 1.8rem; font-weight: 800; color: var(--primary); letter-spacing: -1px; background: linear-gradient(45deg, #2979ff, #00d4ff); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }

.nav-pill { 
    padding: 10px 30px; border-radius: 12px; cursor: pointer; position: relative; color: var(--text-sub); transition: var(--anim); 
}
.nav-pill.active { color: var(--primary); background: var(--primary-soft); }
.nav-pill.active::after { content: ''; position: absolute; bottom: -14px; left: 0; width: 100%; height: 3px; background: var(--primary); border-radius: 2px 2px 0 0; }

.user-menu { display: flex; align-items: center; gap: 12px; cursor: pointer; padding: 5px 10px; border-radius: 50px; transition: var(--anim); }
.user-menu:hover { background: var(--border); }
.user-avatar-sm { width: 36px; height: 36px; border-radius: 50%; object-fit: cover; border: 2px solid var(--surface); box-shadow: 0 2px 5px rgba(0,0,0,0.1); }

/* --- LAYOUT --- */
.layout-grid {
    display: grid; grid-template-columns: 280px 600px 280px; gap: 30px;
    max-width: 1220px; margin: 20px auto; padding: 0 20px;
}

/* --- SIDEBARS --- */
.card { background: var(--surface); border-radius: var(--radius); box-shadow: var(--shadow); overflow: hidden; }
.sidebar-item { display: flex; align-items: center; gap: 12px; padding: 12px; border-radius: 8px; cursor: pointer; font-weight: 500; transition: var(--anim); color: var(--text-sub); }
.sidebar-item:hover { background: var(--border); color: var(--text); transform: translateX(5px); }
.sidebar-icon { width: 36px; height: 36px; display: flex; align-items: center; justify-content: center; border-radius: 50%; background: var(--primary-soft); color: var(--primary); font-size: 1.1rem; }

/* --- FEED & POSTS --- */
.create-box { padding: 20px; margin-bottom: 24px; }
.create-top { display: flex; gap: 15px; margin-bottom: 15px; }
.create-input {
    flex: 1; border: none; background: var(--bg); border-radius: 24px; padding: 12px 20px;
    font-size: 1rem; color: var(--text); transition: var(--anim);
}
.create-input:focus { background: var(--border); box-shadow: 0 0 0 2px var(--primary-soft); }

.create-actions { border-top: 1px solid var(--border); padding-top: 15px; display: flex; justify-content: space-between; align-items: center; }
.action-pill { display: flex; align-items: center; gap: 8px; padding: 8px 12px; border-radius: 8px; cursor: pointer; font-weight: 600; color: var(--text-sub); font-size: 0.9rem; transition: var(--anim); }
.action-pill:hover { background: var(--bg); }

.post-btn {
    background: var(--primary); color: white; border: none; padding: 10px 24px;
    border-radius: 8px; font-weight: 600; cursor: pointer; box-shadow: 0 4px 12px var(--primary-soft);
    transform: scale(0.98); opacity: 0.7; pointer-events: none; transition: var(--anim);
}
.post-btn.ready { transform: scale(1); opacity: 1; pointer-events: all; }
.post-btn:hover { transform: translateY(-2px); box-shadow: 0 6px 16px var(--primary-soft); }

/* POST DESIGN */
.post-card { margin-bottom: 20px; animation: slideUp 0.4s ease-out; }
@keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }

.post-header { padding: 16px; display: flex; align-items: center; gap: 12px; }
.post-meta h4 { font-size: 0.95rem; font-weight: 700; margin-bottom: 2px; }
.post-meta span { font-size: 0.8rem; color: var(--text-sub); display: flex; align-items: center; gap: 5px; }
.post-body { padding: 4px 16px 16px; font-size: 1rem; line-height: 1.5; color: var(--text); }
.post-stats { padding: 12px 16px; border-top: 1px solid var(--border); display: flex; justify-content: space-between; font-size: 0.9rem; color: var(--text-sub); }
.post-footer { padding: 6px 16px; border-top: 1px solid var(--border); display: flex; gap: 5px; }

.interact-btn {
    flex: 1; display: flex; align-items: center; justify-content: center; gap: 8px;
    padding: 10px; border-radius: 6px; cursor: pointer; color: var(--text-sub); font-weight: 600; transition: var(--anim);
}
.interact-btn:hover { background: var(--bg); }
.interact-btn.active { color: var(--primary); background: var(--primary-soft); }
.interact-btn i { font-size: 1.2rem; transition: transform 0.2s; }
.interact-btn:active i { transform: scale(1.3); }

/* COMMENTS */
.comments-wrap { background: var(--bg); padding: 10px 16px; border-radius: 0 0 12px 12px; display: none; }
.comment-item { display: flex; gap: 10px; margin-bottom: 10px; }
.comment-bubble { background: var(--surface); padding: 10px 14px; border-radius: 18px; box-shadow: 0 1px 2px rgba(0,0,0,0.05); }
.comment-author { font-weight: 700; font-size: 0.85rem; margin-bottom: 2px; }
.comment-input-row { display: flex; gap: 10px; margin-top: 10px; }
.comment-field { flex: 1; border: 1px solid var(--border); border-radius: 20px; padding: 8px 15px; font-size: 0.9rem; }

/* LOADING & TOASTS */
.loader { border: 3px solid var(--bg); border-top: 3px solid var(--primary); border-radius: 50%; width: 20px; height: 20px; animation: spin 1s linear infinite; display: none; }
@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

.toast {
    position: fixed; bottom: 30px; left: 50%; transform: translateX(-50%) translateY(100px);
    background: #333; color: white; padding: 12px 24px; border-radius: 50px;
    font-size: 0.9rem; font-weight: 500; opacity: 0; transition: var(--anim); z-index: 2000;
    box-shadow: 0 10px 20px rgba(0,0,0,0.2); display: flex; align-items: center; gap: 10px;
}
.toast.show { transform: translateX(-50%) translateY(0); opacity: 1; }

/* USER SWITCHER MODAL */
.modal-overlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0,0,0,0.5); backdrop-filter: blur(4px); z-index: 3000;
    display: none; align-items: center; justify-content: center;
}
.modal-box { background: var(--surface); padding: 30px; border-radius: 16px; width: 350px; text-align: center; box-shadow: 0 20px 40px rgba(0,0,0,0.2); }
.user-option { display: flex; align-items: center; gap: 15px; padding: 15px; border: 1px solid var(--border); border-radius: 12px; margin-bottom: 10px; cursor: pointer; transition: var(--anim); }
.user-option:hover { border-color: var(--primary); background: var(--primary-soft); }

/* RESPONSIVE */
@media(max-width: 1024px) { .layout-grid { grid-template-columns: 240px 1fr; padding: 0 10px; } .right-sidebar { display: none; } }
@media(max-width: 768px) { .layout-grid { grid-template-columns: 1fr; padding: 0; } .left-sidebar { display: none; } .app-header { padding: 0 15px; } }

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;

// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//

body.script:
    // --- DEEP LOGIC ENGINE ---

    // 1. Initial Data Structure
    const DB_KEY = 'fb_deep_db_v1';
    let db = {
        currentUser: 'Ali Khan',
        posts: [
            {
                id: 1,
                author: 'Bannu Admin',
                avatar: 'https://ui-avatars.com/api/?name=Admin&background=000&color=fff',
                text: 'Welcome to the new Deep Facebook for Bannu City! Try posting, liking, and commenting.',
                time: 'Just now',
                likes: [],
                comments: []
            }
        ]
    };

    // 2. Initialize
    function init() {
        const stored = localStorage.getItem(DB_KEY);
        if (stored) db = JSON.parse(stored);

        updateUserInterface();

        // Simulate Network Delay for Feed Load
        setTimeout(() => {
            document.getElementById('skeleton-loader').style.display = 'none';
            renderFeed();
        }, 800);
    }

    // 3. User Management
    function getAvatar(name) {
        let color = '000';
        if(name.includes('Ali')) color = '0D8ABC';
        if(name.includes('Sana')) color = 'e91e63';
        if(name.includes('Wazir')) color = '4caf50';
        return `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=${color}&color=fff`;
    }

    function updateUserInterface() {
        const avatar = getAvatar(db.currentUser);
        document.getElementById('header-avatar').src = avatar;
        document.getElementById('create-avatar').src = avatar;
        document.getElementById('header-username').innerText = db.currentUser.split(' ')[0];
    }

    function toggleUserModal() {
        const modal = document.getElementById('user-modal');
        modal.style.display = modal.style.display === 'flex' ? 'none' : 'flex';
    }

    function switchUser(name) {
        db.currentUser = name;
        saveDB();
        updateUserInterface();
        toggleUserModal();
        showToast(`Switched to ${name}`);
        renderFeed(); // Re-render to update like button states
    }

    // 4. Post Logic
    function checkInput() {
        const val = document.getElementById('post-input').value;
        const btn = document.getElementById('post-btn');
        if (val.trim().length > 0) btn.classList.add('ready');
        else btn.classList.remove('ready');
    }

    function handlePost() {
        const input = document.getElementById('post-input');
        const btn = document.getElementById('post-btn');
        const loader = btn.querySelector('.loader');
        const textBtn = btn.querySelector('.btn-text');

        // Simulate Loading
        textBtn.style.display = 'none';
        loader.style.display = 'block';

        setTimeout(() => {
            // Create Post Data
            const newPost = {
                id: Date.now(),
                author: db.currentUser,
                avatar: getAvatar(db.currentUser),
                text: input.value,
                time: 'Just now',
                likes: [],
                comments: []
            };

            db.posts.unshift(newPost);
            saveDB();

            // Reset UI
            loader.style.display = 'none';
            textBtn.style.display = 'block';
            input.value = '';
            btn.classList.remove('ready');

            renderFeed();
            showToast('Post Published');
        }, 600);
    }

    // 5. Interaction Logic
    function toggleLike(id) {
        const post = db.posts.find(p => p.id === id);
        if(post.likes.includes(db.currentUser)) {
            post.likes = post.likes.filter(u => u !== db.currentUser);
        } else {
            post.likes.push(db.currentUser);
        }
        saveDB();
        renderFeed();
    }

    function toggleComments(id) {
        const wrap = document.getElementById(`comments-${id}`);
        wrap.style.display = wrap.style.display === 'block' ? 'none' : 'block';
    }

    function submitComment(e, id) {
        if(e.key === 'Enter') {
            const input = e.target;
            if(input.value.trim() === '') return;

            const post = db.posts.find(p => p.id === id);
            post.comments.push({
                author: db.currentUser,
                text: input.value
            });
            saveDB();
            renderFeed();
            // Keep comment section open and focus
            setTimeout(() => {
                document.getElementById(`comments-${id}`).style.display = 'block';
                document.getElementById(`comment-input-${id}`).focus();
            }, 50);
        }
    }

    function deletePost(id) {
        if(confirm('Delete this post?')) {
            db.posts = db.posts.filter(p => p.id !== id);
            saveDB();
            renderFeed();
            showToast('Post Deleted');
        }
    }

    // 6. Rendering
    function renderFeed() {
        const container = document.getElementById('feed-container');
        container.innerHTML = ''; // Clear

        db.posts.forEach(post => {
            const isLiked = post.likes.includes(db.currentUser);
            const activeClass = isLiked ? 'active' : '';
            const likeIcon = isLiked ? 'fas fa-thumbs-up' : 'far fa-thumbs-up';

            // Comments HTML
            let commentsHTML = '';
            post.comments.forEach(c => {
                commentsHTML += `






${c.author}
                            ${c.text}


                `;
            });

            const html = `








${post.author}
                            ${post.time} 





                        ${post.text}



                         ${post.likes.length > 0 ? post.likes.length : ''}
                        ${post.comments.length} Comments





                             Like



                             Comment



                             Share




                        ${commentsHTML}







            `;
            container.insertAdjacentHTML('beforeend', html);
        });
    }

    // 7. Utilities
    function saveDB() {
        localStorage.setItem(DB_KEY, JSON.stringify(db));
    }
    function showToast(msg) {
        const t = document.getElementById('toast');
        document.getElementById('toast-msg').innerText = msg;
        t.classList.add('show');
        setTimeout(() => t.classList.remove('show'), 3000);
    }
    function resetData() {
        if(confirm('Reset Everything?')) {
            localStorage.removeItem(DB_KEY);
            location.reload();
        }
    }

    // Start
    init();
